import React, { useState, useEffect } from 'react';
import Helmet from 'react-helmet';
import L from 'leaflet';
import CovidDashboard from 'components/CovidDashboard';
//import { Marker } from 'react-leaflet';
import axios from 'axios';
import { useTracker } from 'hooks';

//import { promiseToFlyTo, getCurrentLocation } from 'lib/map';
import Layout from 'components/Layout';
import Container from 'components/Container';
import Map from 'components/Map';

const LOCATION = {
  lat: 0,
  lng: 0,
};
const CENTER = [LOCATION.lat, LOCATION.lng];
const DEFAULT_ZOOM = 2;

const IndexPage = () => {
  /**
   * mapEffect
   * @description Fires a callback once the page renders
   * @example Here this is and example of being used to zoom in and set a popup on load
   */
  const [States, setStates] = useState([]);
  const [StatesName, setStateName] = useState([]);
  const [StatesDeath, setStateDeath] = useState([]);




  const stateNames = [
    'Alabama',
    'Alaska',
    'Arizona',
    'Arkansas',
    'California',
    'Colorado',
    'Connecticut',
    'Delaware',
    'Florida',
    'Georgia',
    'Hawaii',
    'Idaho',
    'Illinois',
    'Indiana',
    'Iowa',
    'Kansas',
    'Kentucky',
    'Louisiana',
    'Maine',
    'Maryland',
    'Massachusetts',
    'Michigan',
    'Minnesota',
    'Mississippi',
    'Missouri',
    'Montana',
    'Nebraska',
    'Nevada',
    'New Hampshire',
    'New Jersey',
    'New Mexico',
    'New York',
    'North Carolina',
    'North Dakota',
    'Ohio',
    'Oklahoma',
    'Oregon',
    'Pennsylvania',
    'Rhode Island',
    'South Carolina',
    'South Dakota',
    'Tennessee',
    'Texas',
    'Utah',
    'Vermont',
    'Virginia',
    'Washington',
    'West Virginia',
    'Wisconsin',
    'Wyoming',
  ];

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await axios.get('https://disease.sh/v3/covid-19/states');
        const { data } = response;
        
        const newArray = data.map(state => `${state.state}`);
        const newnewArray = data.map(state => `${state.cases}`);
        const newnewnewArray = data.map(state => `${state.deaths}`);


        setStates(newArray);
        setStateName(newnewArray);
        setStateDeath(newnewnewArray)
      } catch (error) {
        console.error('Error fetching data: ', error);
      }
    };

    fetchData(); 
  }, []); 

  async function mapEffect({ leafletElement: map } = {}) {
    if ( !map ) return;
    // Attempt to fetch data
    let response;
    try {
      response = await axios.get( 'https://disease.sh/v3/covid-19/countries' );
      console.log( 'Response: ', response );
    } catch ( e ) {
      console.error( 'Error fetching data: ', e );
    }

    // Destructure data
    const { data } = response;
    const hasData = Array.isArray( data ) && data.length > 0;
    // If there is no data (error), return
    if ( !hasData ) return;
    if (hasData) {
      // Access information for each country
      data.forEach(country => {
        const countryName = country.country;
        const cases = country.cases;

    //    console.log(`${countryName}: Cases - ${cases}`);
        // You can access other properties like deaths, recovered, etc. in a similar way
      });
    }
    // Transform data to GeoJSON
    const geoJSON = {
      type: 'FeatureCollection',
      features: data.map(( country = {}) => {
        const { countryInfo = {} } = country;
        const { lat, long: lng } = countryInfo;

        return {
          type: 'Feature',
          properties: {
            ...country,
          },
          geometry: {
            type: 'Point',
            coordinates: [lng, lat],
          },
        };
      }),
    };
    
    function countryPointToLayer( feature = {}, latlng ) {
      const { properties = {} } = feature;
      let updateFormatted;
      let caseString;

      // destructure data
      const { country, updated, cases, deaths, recovered } = properties;

      caseString = `${cases}`;

      if ( cases > 1000 ) {
        caseString = `${caseString.slice( 0, -3 )}k+`;
      }

      if ( updated ) {
        updateFormatted = new Date( updated ).toLocaleString();
      }

      const html = `
<span class="icon-marker">
    <span class="icon-marker-tooltip">
        <h2>${country}</h2>
        <ul>
            <li><strong>Confirmed: </strong>${cases}</li>
            <li><strong>Deaths: </strong>${deaths}</li>
            <li><strong>Recovered: </strong>${recovered}</li>
            <li><strong>Last Update: </strong>${updateFormatted}</li>
        </ul>
    </span>
    ${caseString}
</span>
`;
      return L.marker( latlng, {
        icon: L.divIcon({
          className: 'icon',
          html,
        }),
        riseOnHover: true,
      });
    }

    // Insert GeoJSON into map
    const geoJSONLayers = new L.GeoJSON( geoJSON, {
      pointToLayer: countryPointToLayer,
    });
    geoJSONLayers.addTo( map );
  }

  const mapSettings = {
    center: CENTER,
    defaultBaseMap: 'MapBox',
    zoom: DEFAULT_ZOOM,
    mapEffect,
  };

  return (
    <Layout pageName="home">
      <Helmet>
        <title>Home Page</title>
      </Helmet>

      <Map {...mapSettings} />
      <CovidDashboard stateCase = {StatesName} stateName={States}  stateDeath={StatesDeath}/>
        
      <Container type="content" className="text-center home-start">
        <h2>Still Getting Started?</h2>
        <p>Run the following in your terminal!</p>
        <pre>
          <code>gatsby new [directory] https://github.com/colbyfayock/gatsby-starter-leaflet</code>
        </pre>
        <p className="note">Note: Gatsby CLI required globally for the above command</p>
      </Container>
    </Layout>
  );
};

export default IndexPage;